import React from 'react';
import './ImpactPanel.css';

export default function ImpactPanel({ impact, co2, trees, landfill, energy, single }) {
  // single-item mode: show per-item numbers
  const d = single
    ? {
        co2:     impact.co2Saved,
        energy:  impact.energySaved,
        landfill:impact.landfillSaved,
        trees:   impact.treeDays,
      }
    : { co2, trees, landfill, energy };

  const items = [
    { icon: '🌫️', value: d.co2?.toFixed(2) + ' kg',    label: 'CO₂ Prevented' },
    { icon: '🗑️', value: d.landfill?.toFixed(2) + ' kg',label: 'Landfill Avoided' },
    { icon: '⚡', value: d.energy?.toFixed(2) + ' kWh', label: 'Energy Saved' },
    { icon: '🌳', value: d.trees?.toFixed(1) + ' days',  label: 'Tree Equivalent' },
  ];

  return (
    <div className="impact-panel">
      <h3 className="impact-title">🌍 Environmental Impact</h3>
      <div className="impact-grid">
        {items.map((it, i) => (
          <div className="impact-tile" key={i}>
            <span className="impact-tile-icon">{it.icon}</span>
            <span className="impact-tile-value">{it.value}</span>
            <span className="impact-tile-label">{it.label}</span>
          </div>
        ))}
      </div>
    </div>
  );
}
